const finalAnalysis = $node["Parser Analyse Finale"].json || {};
const nextStep = $node["Determiner Prochaine Etape"].json || {};
const webhookRaw = $node["Quiz Webhook"].json || {};
const body = webhookRaw.body && typeof webhookRaw.body === 'object' ? webhookRaw.body : webhookRaw;

const answers = (() => {
  try {
    return JSON.parse(nextStep.answersJSON || '[]');
  } catch (e) {
    return [];
  }
})();

const userId = Number(body.userId || 0);
const analysis = String(finalAnalysis.analysis || '');
const score = Number(finalAnalysis.score || 0);

const hashString = (str) => {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return (h >>> 0).toString(16);
};

const analysisHash = hashString(`${userId}|${analysis}`);
const idempotencyKey = `${userId}:${analysisHash}`;

return {
  status: 'complete',
  analysis,
  score,
  userId,
  answers,
  analysisHash,
  idempotencyKey
};

